using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    private const int maxHealth = 100;

    public void TakeDamage(int damage)
    {
        if (damage < 0) return; // Validate input
        health = Mathf.Clamp(health - damage, 0, maxHealth);
    }

    public void Heal(int amount)
    {
        if (amount < 0) return; // Validate input
        health = Mathf.Clamp(health + amount, 0, maxHealth);
    }

    public bool PurchaseItem(int itemPrice)
    {
        if (itemPrice < 0 || itemPrice > currency) return false; // Validate input
        currency -= itemPrice;
        return true;
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void BuyHealthPotion()
    {
        int potionPrice = 10; // Example price
        if (playerStats.PurchaseItem(potionPrice))
        {
            playerStats.Heal(20); // Heal amount
        }
    }

    public void BuyCurrency(int amount)
    {
        int currencyPrice = amount * 2; // Example price calculation
        if (playerStats.PurchaseItem(currencyPrice))
        {
            playerStats.currency += amount;
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;

    private void Start()
    {
        // Initialize player stats securely
        playerStats.health = Mathf.Clamp(playerStats.health, 0, 100);
        playerStats.currency = 0; // Start with zero currency
    }
}